---
/**
 * @component Accordion
 * @title Accordion
 * @description Vertically stacked collapsible sections that let users show and hide content panels.
 * @figmaUrl https://www.figma.com/design/koxai7zw5vIuBzuVxe5T2l/BejamasUI---Design-System?node-id=2589-14086&t=YFStJ3V8fXEO8QD8-4
 *
 * @preview
 *
 * <Accordion class="w-full max-w-[420px] self-start mt-10" defaultValue="accordion-item-1">
 *   <AccordionItem value="accordion-item-1">
 *     <AccordionTrigger>
 *       Is it accessible?
 *     </AccordionTrigger>
 *     <AccordionContent>
 *       Yes. It adheres to WAI-ARIA design patterns.
 *     </AccordionContent>
 *   </AccordionItem>
 *   <AccordionItem value="accordion-item-2">
 *     <AccordionTrigger>
 *       Can I customize the icon?
 *     </AccordionTrigger>
 *     <AccordionContent>
 *       Yes you can.
 *     </AccordionContent>
 *   </AccordionItem>
 * </Accordion>
 *
 * @usage
 *
 * ```astro nocollapse
 * ---
 * import { Accordion, AccordionItem, AccordionTrigger, AccordionContent } from '@bejamas/ui/components/accordion';
 * ---
 *
 * <Accordion class="w-full max-w-[420px] self-start" defaultValue="accordion-item-1">
 *   <AccordionItem value="accordion-item-1">
 *     <AccordionTrigger>
 *       Is it accessible?
 *     </AccordionTrigger>
 *     <AccordionContent>
 *       Yes. It adheres to WAI-ARIA design patterns.
 *     </AccordionContent>
 *   </AccordionItem>
 * </Accordion>
 * ```
 *
 * @api
 *
 * ### Events
 *
 * The accordion emits custom events that you can listen to:
 *
 * | Event | Detail | Description |
 * |-------|--------|-------------|
 * | `accordion:change` | `{ value: string[] }` | Fired when expanded items change |
 *
 * ```astro nocollapse
 * <Accordion id="my-accordion">
 *   <AccordionItem value="item-1">
 *     <AccordionTrigger>Item 1</AccordionTrigger>
 *     <AccordionContent>Content 1</AccordionContent>
 *   </AccordionItem>
 * </Accordion>
 * ```
 *
 * ```js nocollapse
 *   const accordion = document.getElementById('my-accordion');
 *
 *   accordion.addEventListener('accordion:change', (e) => {
 *     console.log('Expanded items:', e.detail.value);
 *   });
 * ```
 *
 * ### Programmatic Control
 *
 * You can control the accordion programmatically by dispatching an `accordion:set` event:
 *
 * ```js nocollapse
 * const accordion = document.getElementById('my-accordion');
 *
 * // Expand a single item
 * accordion.dispatchEvent(new CustomEvent('accordion:set', {
 *   detail: { value: 'item-1' }
 * }));
 *
 * // Expand multiple items (when multiple prop is true)
 * accordion.dispatchEvent(new CustomEvent('accordion:set', {
 *   detail: { value: ['item-1', 'item-2'] }
 * }));
 * ```
 *
 * ### Data Attributes
 *
 * The accordion sets these data attributes that you can use for styling or querying state:
 *
 * | Attribute | Element | Description |
 * |-----------|---------|-------------|
 * | `data-state` | accordion-item | Current state (`open` or `closed`) |
 *
 * @examples
 *
 * ### Multiple choice accordion
 *
 * <Accordion class="w-full max-w-[420px] self-start" multiple defaultValue={["accordion-item-1"]}>
 *   <AccordionItem value="accordion-item-1">
 *     <AccordionTrigger>
 *       Is it accessible?
 *     </AccordionTrigger>
 *     <AccordionContent>
 *       Yes. It adheres to WAI-ARIA design patterns.
 *     </AccordionContent>
 *   </AccordionItem>
 *   <AccordionItem value="accordion-item-2">
 *     <AccordionTrigger>
 *       Can I customize the icon?
 *     </AccordionTrigger>
 *     <AccordionContent>
 *       Yes you can.
 *     </AccordionContent>
 *   </AccordionItem>
 *   <AccordionItem value="accordion-item-3">
 *     <AccordionTrigger>
 *       Can I customize the icon?
 *     </AccordionTrigger>
 *     <AccordionContent>
 *       Yes you can.
 *     </AccordionContent>
 *   </AccordionItem>
 * </Accordion>
 *
 */

import { cn } from "@bejamas/ui/lib/utils";
import type { HTMLAttributes } from "astro/types";

interface Props extends HTMLAttributes<"div"> {
  class?: string;
  multiple?: boolean;
  defaultValue?: string | string[];
  collapsible?: boolean;
}

const {
  class: className = "",
  multiple = false,
  defaultValue,
  collapsible = true,
  ...rest
} = Astro.props as Props;

const serializedDefaultValue =
  Array.isArray(defaultValue) && defaultValue.length > 0
    ? JSON.stringify(defaultValue)
    : undefined;
---

<div
  {...rest}
  data-slot="accordion"
  data-multiple={multiple ? "true" : undefined}
  data-default-value={typeof defaultValue === "string" ? defaultValue : undefined}
  data-default-value-json={serializedDefaultValue}
  data-collapsible={collapsible ? undefined : "false"}
  class={cn(
    "cn-accordion flex w-full flex-col [&:not([data-enhanced])_[data-slot=accordion-content]]:hidden",
    className,
  )}
>
  <slot />
</div>

<script>
  import { createAccordion } from "@data-slot/accordion";

  const parseBooleanDataAttribute = (
    value,
    fallback,
  ) => (value === undefined ? fallback : value !== "false");

  const parseDefaultValue = (el) => {
    const serializedValues = el.dataset.defaultValueJson;

    if (serializedValues) {
      try {
        const parsed = JSON.parse(serializedValues);

        if (Array.isArray(parsed)) {
          return parsed.filter((value) => typeof value === "string");
        }
      } catch {
        // Fall back to the single-value data attribute.
      }
    }

    const defaultValue = el.dataset.defaultValue;

    return defaultValue === undefined || defaultValue === "" ? undefined : defaultValue;
  };

  document
    .querySelectorAll('[data-slot="accordion"]')
    .forEach((el) => {
      createAccordion(el, {
        multiple: parseBooleanDataAttribute(el.dataset.multiple, false),
        collapsible: parseBooleanDataAttribute(el.dataset.collapsible, true),
        defaultValue: parseDefaultValue(el),
      });
      el.setAttribute("data-enhanced", "");
    });
</script>

