import { cn } from "@bejamas/ui/lib/utils";
import type { HTMLAttributes } from "astro/types";

interface Props extends HTMLAttributes<"div"> {
  class?: string;
}

const { class: className = "", ...rest } = Astro.props as Props;
---

<div
  {...rest}
  data-slot="accordion-content"
  class="cn-accordion-content data-open:animate-accordion-down data-closed:animate-accordion-up text-sm overflow-hidden"
>
  <div
    class={cn(
      "cn-accordion-content-inner h-(--accordion-panel-height) data-ending-style:h-0 data-starting-style:h-0 pt-0 pb-4 [&_a]:underline [&_a]:underline-offset-3 [&_a]:hover:text-foreground [&_p:not(:last-child)]:mb-4",
      className,
    )}
  >
    <slot />
  </div>
</div>

---
import { cn } from "@bejamas/ui/lib/utils";
import type { HTMLAttributes } from "astro/types";

interface Props extends HTMLAttributes<"div"> {
  value: string;
  class?: string;
}

const { value, class: className = "", ...rest } = Astro.props as Props;
---

<div
  {...rest}
  data-value={value}
  data-slot="accordion-item"
  class={cn("cn-accordion-item not-last:border-b", className)}
>
  <slot />
</div>

---
import { cva } from "class-variance-authority";
import { cn } from "@bejamas/ui/lib/utils";
import type { HTMLAttributes } from "astro/types";
import SemanticIcon from "../icon/SemanticIcon.astro";

interface Props extends HTMLAttributes<"button"> {
  class?: string;
  /** Radix-like: render wrapper so the child can be the interactive element */
  asChild?: boolean;
}

const { class: className = "", asChild = false, type = "button", ...rest } = Astro.props as Props;

const triggerVariants = cva(
  "cn-accordion-trigger focus-visible:ring-ring/50 focus-visible:border-ring focus-visible:after:border-ring **:data-[slot=accordion-trigger-icon]:text-muted-foreground rounded-md py-4 text-left text-sm font-medium hover:underline focus-visible:ring-3 **:data-[slot=accordion-trigger-icon]:ml-auto **:data-[slot=accordion-trigger-icon]:size-4 group/accordion-trigger relative flex flex-1 items-start justify-between border border-transparent transition-all outline-none aria-disabled:pointer-events-none aria-disabled:opacity-50",
);
---

{
  asChild ? (
    <div class="flex">
      <div
        data-slot="accordion-trigger"
        data-as-child
        class={cn(triggerVariants(), className)}
      >
        <slot />
      </div>
    </div>
  ) : (
    <div class="flex">
      <button
        {...rest}
        type={type}
        data-slot="accordion-trigger"
        class={cn(triggerVariants(), className)}
      >
        <slot />
        {
          Astro.slots.has("icon") ? (
            <span
              data-slot="accordion-trigger-icon"
              class="cn-accordion-trigger-icon pointer-events-none shrink-0"
            >
              <slot name="icon" />
            </span>
          ) : (
            <>
              <SemanticIcon
                name="chevron-down"
                data-slot="accordion-trigger-icon"
                class="cn-accordion-trigger-icon pointer-events-none shrink-0 group-aria-expanded/accordion-trigger:hidden"
                aria-hidden="true"
              />
              <SemanticIcon
                name="chevron-up"
                data-slot="accordion-trigger-icon"
                class="cn-accordion-trigger-icon pointer-events-none hidden shrink-0 group-aria-expanded/accordion-trigger:inline"
                aria-hidden="true"
              />
            </>
          )
        }
      </button>
    </div>
  )
}

export { default as Accordion } from "./Accordion.astro";
export { default as AccordionItem } from "./AccordionItem.astro";
export { default as AccordionTrigger } from "./AccordionTrigger.astro";
export { default as AccordionContent } from "./AccordionContent.astro";
